-- ============================================================
-- GameForge AI — Community Enhancements
-- Adds creator_name, seeds community games, adds view tracking
-- ============================================================

-- Add creator_name column for community display
ALTER TABLE game_projects ADD COLUMN IF NOT EXISTS creator_name TEXT;

-- View count increment function (for public play page)
CREATE OR REPLACE FUNCTION increment_views(p_game_id UUID)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  UPDATE game_projects
  SET views_count = views_count + 1
  WHERE id = p_game_id AND is_public = true;
END;
$$;

-- Seed mock community games for demo purposes
-- These use a NULL studio_id (orphaned) since they're mock data for display only
-- They're visible via the is_public = true RLS policy

DO $$
DECLARE
  v_mock_studio_id UUID;
BEGIN
  -- Create a mock "community" studio for seeded games
  INSERT INTO studios (name, owner_id, subscription_tier)
  VALUES ('GameForge Community', '00000000-0000-0000-0000-000000000000', 'free')
  ON CONFLICT DO NOTHING
  RETURNING id INTO v_mock_studio_id;

  -- Only seed if studio was created (first run)
  IF v_mock_studio_id IS NOT NULL THEN

    -- 1. Asteroid Storm (shooter) — by NeonByte Studios
    INSERT INTO game_projects (studio_id, name, description, genre, status, game_code, is_public, likes_count, views_count, creator_name)
    VALUES (v_mock_studio_id, 'Asteroid Storm', 'Dodge and destroy asteroids in deep space — survive the storm', 'shooter', 'published',
    '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Asteroid Storm</title><style>*{margin:0;padding:0}body{background:#000;display:flex;justify-content:center;align-items:center;min-height:100vh;overflow:hidden}</style><script src="https://cdn.jsdelivr.net/npm/phaser@3/dist/phaser.min.js"></script></head><body><script>class G extends Phaser.Scene{constructor(){super("game")}create(){this.score=0;this.lives=3;this.gameOver=false;this.player=this.add.triangle(400,500,0,20,10,0,20,20,0x00FFFF);this.physics.add.existing(this.player);this.player.body.setCollideWorldBounds(true);this.cursors=this.input.keyboard.createCursorKeys();this.bullets=this.physics.add.group();this.rocks=this.physics.add.group();this.scoreText=this.add.text(16,16,"SCORE: 0",{fontFamily:"monospace",fontSize:"18px",fill:"#00FFFF"});this.livesText=this.add.text(700,16,"LIVES: 3",{fontFamily:"monospace",fontSize:"18px",fill:"#FED985"});this.input.keyboard.on("keydown-SPACE",()=>{if(!this.gameOver){let b=this.add.circle(this.player.x,this.player.y-15,3,0x00FFFF);this.physics.add.existing(b);b.body.setVelocityY(-500);this.bullets.add(b);}});this.time.addEvent({delay:700,callback:()=>{if(!this.gameOver){let x=Phaser.Math.Between(30,770);let s=Phaser.Math.Between(15,25);let r=this.add.circle(x,-20,s,0x888888);this.physics.add.existing(r);r.body.setVelocityY(Phaser.Math.Between(100,250));r.body.setVelocityX(Phaser.Math.Between(-50,50));this.rocks.add(r);}},loop:true});this.physics.add.overlap(this.bullets,this.rocks,(b,r)=>{b.destroy();r.destroy();this.score+=15;this.scoreText.setText("SCORE: "+this.score);});this.physics.add.overlap(this.player,this.rocks,(p,r)=>{r.destroy();this.lives--;this.livesText.setText("LIVES: "+this.lives);if(this.lives<=0)this.endGame();});}endGame(){this.gameOver=true;this.physics.pause();this.add.rectangle(400,300,800,600,0x000000,0.75);this.add.text(400,240,"GAME OVER",{fontFamily:"monospace",fontSize:"52px",fill:"#FF3131",fontStyle:"bold"}).setOrigin(0.5);this.add.text(400,310,"Score: "+this.score,{fontFamily:"monospace",fontSize:"32px",fill:"#FED985"}).setOrigin(0.5);this.add.text(400,370,"Press SPACE or Click to Restart",{fontFamily:"monospace",fontSize:"20px",fill:"#00FFFF"}).setOrigin(0.5);this.add.rectangle(400,430,180,44,0x006666);this.add.text(400,430,"RESTART",{fontFamily:"monospace",fontSize:"18px",fill:"#fff",fontStyle:"bold"}).setOrigin(0.5);this.input.keyboard.once("keydown-SPACE",()=>this.scene.restart());this.input.once("pointerdown",()=>this.scene.restart());}update(){if(this.gameOver)return;this.player.body.setVelocityX(0);this.player.body.setVelocityY(0);if(this.cursors.left.isDown)this.player.body.setVelocityX(-280);if(this.cursors.right.isDown)this.player.body.setVelocityX(280);if(this.cursors.up.isDown)this.player.body.setVelocityY(-280);if(this.cursors.down.isDown)this.player.body.setVelocityY(280);this.bullets.getChildren().forEach(b=>{if(b.y<0)b.destroy();});this.rocks.getChildren().forEach(r=>{if(r.y>620)r.destroy();});}}new Phaser.Game({type:Phaser.AUTO,width:800,height:600,backgroundColor:"#050520",physics:{default:"arcade",arcade:{gravity:{y:0}}},scene:G});</script></body></html>',
    true, 287, 1432, 'NeonByte Studios');

    -- 2. Gravity Runner (platformer) — by PixelForge
    INSERT INTO game_projects (studio_id, name, description, genre, status, game_code, is_public, likes_count, views_count, creator_name)
    VALUES (v_mock_studio_id, 'Gravity Runner', 'Auto-running platformer — time your jumps perfectly', 'platformer', 'published',
    '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Gravity Runner</title><style>*{margin:0;padding:0}body{background:#000;display:flex;justify-content:center;align-items:center;min-height:100vh;overflow:hidden}</style><script src="https://cdn.jsdelivr.net/npm/phaser@3/dist/phaser.min.js"></script></head><body><script>class G extends Phaser.Scene{constructor(){super("game")}create(){this.score=0;this.gameOver=false;this.speed=4;this.platforms=this.physics.add.staticGroup();this.platforms.add(this.add.rectangle(400,590,800,20,0x333333));this.platforms.getChildren().forEach(p=>p.refreshBody());this.player=this.add.rectangle(150,550,20,28,0xFF6B35);this.physics.add.existing(this.player);this.player.body.setCollideWorldBounds(true);this.obstacles=this.physics.add.group();this.physics.add.collider(this.player,this.platforms);this.physics.add.overlap(this.player,this.obstacles,()=>{if(!this.gameOver)this.endGame();});this.input.keyboard.on("keydown-SPACE",()=>{if(!this.gameOver&&this.player.body.touching.down)this.player.body.setVelocityY(-450);});this.input.on("pointerdown",()=>{if(!this.gameOver&&this.player.body.touching.down)this.player.body.setVelocityY(-450);});this.time.addEvent({delay:1200,callback:()=>{if(!this.gameOver){let h=Phaser.Math.Between(30,70);let o=this.add.rectangle(820,590-h/2,25,h,0xFF3131);this.physics.add.existing(o);o.body.setVelocityX(-200-this.speed*20);o.body.setAllowGravity(false);this.obstacles.add(o);this.speed+=0.3;}},loop:true});this.scoreText=this.add.text(16,16,"SCORE: 0",{fontFamily:"monospace",fontSize:"18px",fill:"#FF6B35"});this.time.addEvent({delay:100,callback:()=>{if(!this.gameOver){this.score++;this.scoreText.setText("SCORE: "+this.score);}},loop:true});}endGame(){this.gameOver=true;this.physics.pause();this.add.rectangle(400,300,800,600,0x000000,0.75);this.add.text(400,240,"GAME OVER",{fontFamily:"monospace",fontSize:"52px",fill:"#FF3131",fontStyle:"bold"}).setOrigin(0.5);this.add.text(400,310,"Score: "+this.score,{fontFamily:"monospace",fontSize:"32px",fill:"#FED985"}).setOrigin(0.5);this.add.text(400,370,"Press SPACE or Click to Restart",{fontFamily:"monospace",fontSize:"20px",fill:"#FF6B35"}).setOrigin(0.5);this.add.rectangle(400,430,180,44,0x993300);this.add.text(400,430,"RESTART",{fontFamily:"monospace",fontSize:"18px",fill:"#fff",fontStyle:"bold"}).setOrigin(0.5);this.input.keyboard.once("keydown-SPACE",()=>this.scene.restart());this.input.once("pointerdown",()=>this.scene.restart());}update(){if(this.gameOver)return;this.obstacles.getChildren().forEach(o=>{if(o.x<-30)o.destroy();});}}new Phaser.Game({type:Phaser.AUTO,width:800,height:600,backgroundColor:"#1a0a0a",physics:{default:"arcade",arcade:{gravity:{y:800}}},scene:G});</script></body></html>',
    true, 412, 2105, 'PixelForge');

    -- 3. Neon Drift (racing) — by RetroMax
    INSERT INTO game_projects (studio_id, name, description, genre, status, game_code, is_public, likes_count, views_count, creator_name)
    VALUES (v_mock_studio_id, 'Neon Drift', 'High-speed lane switching — how far can you drift?', 'racing', 'published',
    '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Neon Drift</title><style>*{margin:0;padding:0}body{background:#000;display:flex;justify-content:center;align-items:center;min-height:100vh;overflow:hidden}</style><script src="https://cdn.jsdelivr.net/npm/phaser@3/dist/phaser.min.js"></script></head><body><script>class G extends Phaser.Scene{constructor(){super("game")}create(){this.score=0;this.gameOver=false;this.speed=180;this.lanes=[200,400,600];this.currentLane=1;for(let i=0;i<3;i++)this.add.rectangle(this.lanes[i],300,2,600,0x222222);this.player=this.add.rectangle(this.lanes[1],520,28,48,0xFF00FF);this.physics.add.existing(this.player);this.player.body.setCollideWorldBounds(true);this.obstacles=this.physics.add.group();this.cursors=this.input.keyboard.createCursorKeys();this.input.keyboard.on("keydown-LEFT",()=>{if(!this.gameOver&&this.currentLane>0){this.currentLane--;this.player.x=this.lanes[this.currentLane];}});this.input.keyboard.on("keydown-RIGHT",()=>{if(!this.gameOver&&this.currentLane<2){this.currentLane++;this.player.x=this.lanes[this.currentLane];}});this.scoreText=this.add.text(16,16,"DISTANCE: 0",{fontFamily:"monospace",fontSize:"18px",fill:"#FF00FF"});this.time.addEvent({delay:500,callback:()=>{if(!this.gameOver){let lane=Phaser.Math.Between(0,2);let o=this.add.rectangle(this.lanes[lane],-30,30,50,0xFFFFFF);this.physics.add.existing(o);o.body.setVelocityY(this.speed);this.obstacles.add(o);this.speed=Math.min(this.speed+2,450);}},loop:true});this.physics.add.overlap(this.player,this.obstacles,()=>{if(!this.gameOver)this.endGame();});this.time.addEvent({delay:100,callback:()=>{if(!this.gameOver){this.score++;this.scoreText.setText("DISTANCE: "+this.score);}},loop:true});}endGame(){this.gameOver=true;this.physics.pause();this.add.rectangle(400,300,800,600,0x000000,0.75);this.add.text(400,220,"WIPEOUT!",{fontFamily:"monospace",fontSize:"52px",fill:"#FF00FF",fontStyle:"bold"}).setOrigin(0.5);this.add.text(400,300,"Distance: "+this.score,{fontFamily:"monospace",fontSize:"32px",fill:"#FED985"}).setOrigin(0.5);this.add.text(400,370,"Press SPACE or Click to Restart",{fontFamily:"monospace",fontSize:"20px",fill:"#FF00FF"}).setOrigin(0.5);this.add.rectangle(400,430,180,44,0x660066);this.add.text(400,430,"RESTART",{fontFamily:"monospace",fontSize:"18px",fill:"#fff",fontStyle:"bold"}).setOrigin(0.5);this.input.keyboard.once("keydown-SPACE",()=>this.scene.restart());this.input.once("pointerdown",()=>this.scene.restart());}update(){if(this.gameOver)return;this.obstacles.getChildren().forEach(o=>{if(o.y>650)o.destroy();});}}new Phaser.Game({type:Phaser.AUTO,width:800,height:600,backgroundColor:"#0a000a",physics:{default:"arcade",arcade:{gravity:{y:0}}},scene:G});</script></body></html>',
    true, 198, 876, 'RetroMax');

    -- 4. Brain Tiles (puzzle) — by 8BitDreams
    INSERT INTO game_projects (studio_id, name, description, genre, status, game_code, is_public, likes_count, views_count, creator_name)
    VALUES (v_mock_studio_id, 'Brain Tiles', 'Memory tile matcher — flip and match pairs before time expires', 'puzzle', 'published',
    '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Brain Tiles</title><style>*{margin:0;padding:0}body{background:#000;display:flex;justify-content:center;align-items:center;min-height:100vh;overflow:hidden}</style><script src="https://cdn.jsdelivr.net/npm/phaser@3/dist/phaser.min.js"></script></head><body><script>class G extends Phaser.Scene{constructor(){super("game")}create(){this.score=0;this.gameOver=false;this.timeLeft=45;this.pairs=0;this.totalPairs=8;this.flipped=[];this.locked=false;this.colors=[0xFF3131,0x7CFC00,0x3B82F6,0xFED985,0xA855F7,0xFF00FF,0x00FFFF,0xFF6B35];let tiles=[];this.colors.forEach((c,i)=>{tiles.push(i,i);});Phaser.Utils.Array.Shuffle(tiles);this.cards=[];let cols=4,rows=4,ts=100,ox=(800-cols*ts)/2,oy=100;for(let i=0;i<16;i++){let r=Math.floor(i/cols),c=i%cols;let x=ox+c*ts+ts/2,y=oy+r*ts+ts/2;let back=this.add.rectangle(x,y,ts-8,ts-8,0x2A2A2A).setInteractive().setStrokeStyle(2,0x444444);let front=this.add.rectangle(x,y,ts-8,ts-8,this.colors[tiles[i]]).setVisible(false);this.cards.push({back,front,colorIdx:tiles[i],revealed:false});back.on("pointerdown",()=>this.flipCard(i));}this.scoreText=this.add.text(16,16,"PAIRS: 0/"+this.totalPairs,{fontFamily:"monospace",fontSize:"18px",fill:"#7CFC00"});this.timerText=this.add.text(700,16,this.timeLeft+"s",{fontFamily:"monospace",fontSize:"18px",fill:"#FED985"});this.time.addEvent({delay:1000,callback:()=>{if(!this.gameOver){this.timeLeft--;this.timerText.setText(this.timeLeft+"s");if(this.timeLeft<=10)this.timerText.setFill("#FF3131");if(this.timeLeft<=0)this.endGame();}},loop:true});}flipCard(i){if(this.locked||this.cards[i].revealed||this.gameOver)return;let card=this.cards[i];card.back.setVisible(false);card.front.setVisible(true);card.revealed=true;this.flipped.push(i);if(this.flipped.length===2){this.locked=true;let[a,b]=this.flipped;if(this.cards[a].colorIdx===this.cards[b].colorIdx){this.pairs++;this.score+=20;this.scoreText.setText("PAIRS: "+this.pairs+"/"+this.totalPairs);this.flipped=[];this.locked=false;if(this.pairs>=this.totalPairs)this.showWin();}else{this.time.delayedCall(600,()=>{this.cards[a].back.setVisible(true);this.cards[a].front.setVisible(false);this.cards[a].revealed=false;this.cards[b].back.setVisible(true);this.cards[b].front.setVisible(false);this.cards[b].revealed=false;this.flipped=[];this.locked=false;});}}}showWin(){this.gameOver=true;this.add.rectangle(400,300,800,600,0x000000,0.8);this.add.text(400,240,"YOU WIN!",{fontFamily:"monospace",fontSize:"52px",fill:"#7CFC00",fontStyle:"bold"}).setOrigin(0.5);this.add.text(400,310,"Time left: "+this.timeLeft+"s",{fontFamily:"monospace",fontSize:"24px",fill:"#FED985"}).setOrigin(0.5);this.add.text(400,370,"Press SPACE or Click to Play Again",{fontFamily:"monospace",fontSize:"20px",fill:"#7CFC00"}).setOrigin(0.5);this.add.rectangle(400,430,180,44,0x47761E);this.add.text(400,430,"PLAY AGAIN",{fontFamily:"monospace",fontSize:"18px",fill:"#fff",fontStyle:"bold"}).setOrigin(0.5);this.input.keyboard.once("keydown-SPACE",()=>this.scene.restart());this.input.once("pointerdown",()=>this.scene.restart());}endGame(){this.gameOver=true;this.add.rectangle(400,300,800,600,0x000000,0.8);this.add.text(400,220,"TIME''S UP!",{fontFamily:"monospace",fontSize:"52px",fill:"#FF3131",fontStyle:"bold"}).setOrigin(0.5);this.add.text(400,300,"Pairs: "+this.pairs+"/"+this.totalPairs,{fontFamily:"monospace",fontSize:"32px",fill:"#FED985"}).setOrigin(0.5);this.add.text(400,370,"Press SPACE or Click to Restart",{fontFamily:"monospace",fontSize:"20px",fill:"#7CFC00"}).setOrigin(0.5);this.add.rectangle(400,430,180,44,0x47761E);this.add.text(400,430,"RESTART",{fontFamily:"monospace",fontSize:"18px",fill:"#fff",fontStyle:"bold"}).setOrigin(0.5);this.input.keyboard.once("keydown-SPACE",()=>this.scene.restart());this.input.once("pointerdown",()=>this.scene.restart());}}new Phaser.Game({type:Phaser.AUTO,width:800,height:600,backgroundColor:"#0f0f1a",scene:G});</script></body></html>',
    true, 156, 723, '8BitDreams');

    -- 5. Shadow Dungeon (rpg) — by CryptVault Games
    INSERT INTO game_projects (studio_id, name, description, genre, status, game_code, is_public, likes_count, views_count, creator_name)
    VALUES (v_mock_studio_id, 'Shadow Dungeon', 'Explore dark corridors — fight shadows, find the golden exit', 'rpg', 'published',
    '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Shadow Dungeon</title><style>*{margin:0;padding:0}body{background:#000;display:flex;justify-content:center;align-items:center;min-height:100vh;overflow:hidden}</style><script src="https://cdn.jsdelivr.net/npm/phaser@3/dist/phaser.min.js"></script></head><body><script>class G extends Phaser.Scene{constructor(){super("game")}create(){this.ts=40;this.hp=5;this.maxHp=5;this.score=0;this.gameOver=false;this.level=1;this.map=["####################","#......#...........#","#.####.#.#########.#","#.#....#.#.......#.#","#.#.##.#.#.#####.#.#","#.#..#.....#.....#.#","#.##.######.####.#.#","#....#............#","#.##.#.########.#.#","#.#..#.#......#.#.#","#.#.##.#.####.#.#.#","#.#....#....#...#.#","#.####.####.###.#.#","#..............#...#","####################"];this.tiles=[];this.enemies=[];this.potions=[];this.drawMap();this.placePlayer();this.placeEnemies();this.placePotions();this.placeExit();this.hpText=this.add.text(16,4,"HP: "+this.hp+"/"+this.maxHp,{fontFamily:"monospace",fontSize:"14px",fill:"#FF3131"}).setDepth(10);this.scoreText=this.add.text(200,4,"SCORE: 0",{fontFamily:"monospace",fontSize:"14px",fill:"#FED985"}).setDepth(10);this.levelText=this.add.text(700,4,"FLOOR "+this.level,{fontFamily:"monospace",fontSize:"14px",fill:"#A855F7"}).setDepth(10);this.cursors=this.input.keyboard.createCursorKeys();this.moveDelay=0;}drawMap(){this.tiles.forEach(t=>t.destroy());this.tiles=[];for(let r=0;r<15;r++)for(let c=0;c<20;c++){let x=c*this.ts+this.ts/2,y=r*this.ts+this.ts/2;if(this.map[r][c]==="#"){this.tiles.push(this.add.rectangle(x,y,this.ts,this.ts,0x1A1A2E).setStrokeStyle(1,0x2A2A3E));}else{this.tiles.push(this.add.rectangle(x,y,this.ts,this.ts,0x0A0A15));}}}isWalk(c,r){return r>=0&&r<15&&c>=0&&c<20&&this.map[r][c]!=="#";}getOpen(){let s=[];for(let r=1;r<14;r++)for(let c=1;c<19;c++)if(this.map[r][c]===".")s.push({r,c});return Phaser.Utils.Array.Shuffle(s);}placePlayer(){let s=this.getOpen()[0];this.pp={r:s.r,c:s.c};if(!this.pr)this.pr=this.add.rectangle(0,0,this.ts-8,this.ts-8,0xA855F7).setDepth(5);this.pr.setPosition(s.c*this.ts+this.ts/2,s.r*this.ts+this.ts/2);}placeEnemies(){this.enemies.forEach(e=>e.rect.destroy());this.enemies=[];let s=this.getOpen().filter(p=>Math.abs(p.r-this.pp.r)+Math.abs(p.c-this.pp.c)>4);for(let i=0;i<Math.min(3+this.level,7);i++){if(!s[i])break;let p=s[i];let rect=this.add.rectangle(p.c*this.ts+this.ts/2,p.r*this.ts+this.ts/2,this.ts-10,this.ts-10,0x666666).setDepth(4);this.enemies.push({r:p.r,c:p.c,rect});}}placePotions(){this.potions.forEach(p=>p.rect.destroy());this.potions=[];let s=this.getOpen().filter(p=>Math.abs(p.r-this.pp.r)+Math.abs(p.c-this.pp.c)>3);for(let i=0;i<2;i++){if(!s[i])break;let p=s[i];let rect=this.add.circle(p.c*this.ts+this.ts/2,p.r*this.ts+this.ts/2,8,0x3B82F6).setDepth(4);this.potions.push({r:p.r,c:p.c,rect});}}placeExit(){if(this.er)this.er.destroy();let s=this.getOpen().filter(p=>Math.abs(p.r-this.pp.r)+Math.abs(p.c-this.pp.c)>6);if(!s.length)s=this.getOpen().slice(-1);let p=s[0];this.ep={r:p.r,c:p.c};this.er=this.add.rectangle(p.c*this.ts+this.ts/2,p.r*this.ts+this.ts/2,this.ts-6,this.ts-6,0xFED985).setStrokeStyle(2,0xFFA500).setDepth(3);}movePlayer(dc,dr){if(this.gameOver)return;let nc=this.pp.c+dc,nr=this.pp.r+dr;if(!this.isWalk(nc,nr))return;let en=this.enemies.find(e=>e.c===nc&&e.r===nr);if(en){en.rect.destroy();this.enemies=this.enemies.filter(e=>e!==en);this.score+=25;this.scoreText.setText("SCORE: "+this.score);return;}this.pp.c=nc;this.pp.r=nr;this.pr.setPosition(nc*this.ts+this.ts/2,nr*this.ts+this.ts/2);let pot=this.potions.find(p=>p.c===nc&&p.r===nr);if(pot){pot.rect.destroy();this.potions=this.potions.filter(p=>p!==pot);this.hp=Math.min(this.hp+2,this.maxHp);this.hpText.setText("HP: "+this.hp+"/"+this.maxHp);}if(nc===this.ep.c&&nr===this.ep.r){this.level++;this.levelText.setText("FLOOR "+this.level);this.score+=100;this.scoreText.setText("SCORE: "+this.score);this.drawMap();this.placePlayer();this.placeEnemies();this.placePotions();this.placeExit();}this.enemies.forEach(e=>{if(Math.random()<0.35){let dx=Math.sign(this.pp.c-e.c),dy=Math.sign(this.pp.r-e.r);let ec=e.c+dx,er=e.r+dy;if(ec===this.pp.c&&er===this.pp.r){this.hp--;this.hpText.setText("HP: "+this.hp+"/"+this.maxHp);if(this.hp<=0)this.endGame();}else if(this.isWalk(ec,er)&&!this.enemies.some(o=>o!==e&&o.c===ec&&o.r===er)){e.c=ec;e.r=er;e.rect.setPosition(ec*this.ts+this.ts/2,er*this.ts+this.ts/2);}}});}endGame(){this.gameOver=true;this.add.rectangle(400,300,800,600,0x000000,0.8).setDepth(20);this.add.text(400,210,"DEFEATED",{fontFamily:"monospace",fontSize:"52px",fill:"#A855F7",fontStyle:"bold"}).setOrigin(0.5).setDepth(21);this.add.text(400,280,"Floor: "+this.level,{fontFamily:"monospace",fontSize:"24px",fill:"#888"}).setOrigin(0.5).setDepth(21);this.add.text(400,320,"Score: "+this.score,{fontFamily:"monospace",fontSize:"32px",fill:"#FED985"}).setOrigin(0.5).setDepth(21);this.add.text(400,380,"Press SPACE or Click to Restart",{fontFamily:"monospace",fontSize:"20px",fill:"#A855F7"}).setOrigin(0.5).setDepth(21);this.add.rectangle(400,440,180,44,0x442266).setDepth(21);this.add.text(400,440,"RESTART",{fontFamily:"monospace",fontSize:"18px",fill:"#fff",fontStyle:"bold"}).setOrigin(0.5).setDepth(21);this.input.keyboard.once("keydown-SPACE",()=>this.scene.restart());this.input.once("pointerdown",()=>this.scene.restart());}update(t){if(this.gameOver)return;if(t<this.moveDelay)return;if(this.cursors.left.isDown){this.movePlayer(-1,0);this.moveDelay=t+150;}else if(this.cursors.right.isDown){this.movePlayer(1,0);this.moveDelay=t+150;}else if(this.cursors.up.isDown){this.movePlayer(0,-1);this.moveDelay=t+150;}else if(this.cursors.down.isDown){this.movePlayer(0,1);this.moveDelay=t+150;}}}new Phaser.Game({type:Phaser.AUTO,width:800,height:600,backgroundColor:"#050510",scene:G});</script></body></html>',
    true, 234, 1089, 'CryptVault Games');

    -- 6. Cyber Snake (other/arcade) — by GlitchLab
    INSERT INTO game_projects (studio_id, name, description, genre, status, game_code, is_public, likes_count, views_count, creator_name)
    VALUES (v_mock_studio_id, 'Cyber Snake', 'Classic snake with a neon twist — grow longer, go faster', 'shooter', 'published',
    '<!DOCTYPE html><html><head><meta charset="utf-8"><title>Cyber Snake</title><style>*{margin:0;padding:0}body{background:#000;display:flex;justify-content:center;align-items:center;min-height:100vh;overflow:hidden}</style><script src="https://cdn.jsdelivr.net/npm/phaser@3/dist/phaser.min.js"></script></head><body><script>class G extends Phaser.Scene{constructor(){super("game")}create(){this.gridSize=20;this.cols=40;this.rows=30;this.snake=[{x:20,y:15},{x:19,y:15},{x:18,y:15}];this.dir={x:1,y:0};this.nextDir={x:1,y:0};this.food=null;this.score=0;this.gameOver=false;this.moveTimer=0;this.speed=120;this.rects=[];this.placeFood();this.scoreText=this.add.text(16,4,"SCORE: 0",{fontFamily:"monospace",fontSize:"16px",fill:"#7CFC00"}).setDepth(2);this.cursors=this.input.keyboard.createCursorKeys();this.input.keyboard.on("keydown-LEFT",()=>{if(this.dir.x!==1)this.nextDir={x:-1,y:0};});this.input.keyboard.on("keydown-RIGHT",()=>{if(this.dir.x!==-1)this.nextDir={x:1,y:0};});this.input.keyboard.on("keydown-UP",()=>{if(this.dir.y!==1)this.nextDir={x:0,y:-1};});this.input.keyboard.on("keydown-DOWN",()=>{if(this.dir.y!==-1)this.nextDir={x:0,y:1};});}placeFood(){let x,y;do{x=Phaser.Math.Between(0,this.cols-1);y=Phaser.Math.Between(0,this.rows-1);}while(this.snake.some(s=>s.x===x&&s.y===y));this.food={x,y};}draw(){this.rects.forEach(r=>r.destroy());this.rects=[];this.snake.forEach((s,i)=>{let color=i===0?0x7CFC00:0x47761E;let r=this.add.rectangle(s.x*this.gridSize+this.gridSize/2,s.y*this.gridSize+this.gridSize/2,this.gridSize-2,this.gridSize-2,color);this.rects.push(r);});if(this.food){let f=this.add.rectangle(this.food.x*this.gridSize+this.gridSize/2,this.food.y*this.gridSize+this.gridSize/2,this.gridSize-2,this.gridSize-2,0xFF3131);this.rects.push(f);}}update(time){if(this.gameOver)return;if(time<this.moveTimer)return;this.moveTimer=time+this.speed;this.dir=this.nextDir;let head={x:this.snake[0].x+this.dir.x,y:this.snake[0].y+this.dir.y};if(head.x<0||head.x>=this.cols||head.y<0||head.y>=this.rows||this.snake.some(s=>s.x===head.x&&s.y===head.y)){this.endGame();return;}this.snake.unshift(head);if(this.food&&head.x===this.food.x&&head.y===this.food.y){this.score+=10;this.scoreText.setText("SCORE: "+this.score);this.speed=Math.max(50,this.speed-2);this.placeFood();}else{this.snake.pop();}this.draw();}endGame(){this.gameOver=true;this.add.rectangle(400,300,800,600,0x000000,0.75).setDepth(10);this.add.text(400,240,"GAME OVER",{fontFamily:"monospace",fontSize:"52px",fill:"#FF3131",fontStyle:"bold"}).setOrigin(0.5).setDepth(11);this.add.text(400,310,"Score: "+this.score,{fontFamily:"monospace",fontSize:"32px",fill:"#FED985"}).setOrigin(0.5).setDepth(11);this.add.text(400,360,"Length: "+this.snake.length,{fontFamily:"monospace",fontSize:"18px",fill:"#888"}).setOrigin(0.5).setDepth(11);this.add.text(400,410,"Press SPACE or Click to Restart",{fontFamily:"monospace",fontSize:"20px",fill:"#7CFC00"}).setOrigin(0.5).setDepth(11);this.add.rectangle(400,470,180,44,0x47761E).setDepth(11);this.add.text(400,470,"RESTART",{fontFamily:"monospace",fontSize:"18px",fill:"#fff",fontStyle:"bold"}).setOrigin(0.5).setDepth(11);this.input.keyboard.once("keydown-SPACE",()=>this.scene.restart());this.input.once("pointerdown",()=>this.scene.restart());}}new Phaser.Game({type:Phaser.AUTO,width:800,height:600,backgroundColor:"#0a0a0a",scene:G});</script></body></html>',
    true, 342, 1678, 'GlitchLab');

